/**
 * Template for TUI Ink components
 */

import { toPascalCase } from '../../generators/utils.js';

export function generateTuiComponentTemplate(name: string): string {
  const pascal = toPascalCase(name);
  return `/**
 * @generated by @flusk/cli — customize after generation
 * TUI Component: ${pascal}
 */

import React from 'react';
import { Box, Text } from 'ink';

export interface ${pascal}Props {
  endpoint: string;
  apiKey: string;
}

export function ${pascal}({ endpoint, apiKey }: ${pascal}Props) {
  return (
    <Box flexDirection="column">
      <Text bold>${pascal}</Text>
      <Text dimColor>TODO: implement ${name} component</Text>
    </Box>
  );
}
`;
}
